#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define STR_SIZE 256

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);
void runTest(int argc, char **argv);

static void srad_omp_1(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    const float *J,
    float *C,
    int cols,
    int rows,
    float q0sqr)
{
#pragma omp parallel for collapse(2)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            int iN = (i == 0) ? 0 : (i - 1);
            int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
            int jW = (j == 0) ? 0 : (j - 1);
            int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

            float jc = J[index];
            float n = J[iN * cols + j] - jc;
            float s = J[iS * cols + j] - jc;
            float w = J[i * cols + jW] - jc;
            float e = J[i * cols + jE] - jc;

            float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
            float l = (n + s + w + e) / jc;

            float num = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
            float den = 1.0f + (0.25f * l);
            float qsqr = num / (den * den);

            den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            float c = 1.0f / (1.0f + den);

            if (c < 0.0f) c = 0.0f;
            else if (c > 1.0f) c = 1.0f;

            C[index] = c;
            E_C[index] = e;
            W_C[index] = w;
            S_C[index] = s;
            N_C[index] = n;
        }
    }
}

static void srad_omp_2(
    const float *E_C,
    const float *W_C,
    const float *N_C,
    const float *S_C,
    float *J,
    const float *C,
    int cols,
    int rows,
    float lambda,
    float q0sqr)
{
    (void)q0sqr;
#pragma omp parallel for collapse(2)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
            int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

            float cc = C[index];
            float cn = cc;
            float cs = C[iS * cols + j];
            float cw = cc;
            float ce = C[i * cols + jE];

            float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];
            J[index] = J[index] + 0.25f * lambda * d_sum;
        }
    }
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

int main(int argc, char **argv)
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);
    return EXIT_SUCCESS;
}

void runTest(int argc, char **argv)
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;
    float *E_C, *W_C, *N_C, *S_C;
    unsigned int r1, r2, c1, c2;
    float *c;

    if (argc == 9) {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = (unsigned int)atoi(argv[3]);
        r2 = (unsigned int)atoi(argv[4]);
        c1 = (unsigned int)atoi(argv[5]);
        c2 = (unsigned int)atoi(argv[6]);
        lambda = (float)atof(argv[7]);
        niter = atoi(argv[8]);
    } else {
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c = (float *)malloc(size_I * sizeof(float));
    E_C = (float *)malloc(size_I * sizeof(float));
    W_C = (float *)malloc(size_I * sizeof(float));
    N_C = (float *)malloc(size_I * sizeof(float));
    S_C = (float *)malloc(size_I * sizeof(float));

    if (!I || !J || !c || !E_C || !W_C || !N_C || !S_C) {
        fprintf(stderr, "memory allocation failed\n");
        free(I);
        free(J);
        free(c);
        free(E_C);
        free(W_C);
        free(N_C);
        free(S_C);
        exit(1);
    }

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }

    printf("Start the SRAD main loop\n");
    for (iter = 0; iter < niter; iter++) {
        sum = 0;
        sum2 = 0;
        for (unsigned int i = r1; i <= r2; i++) {
            for (unsigned int j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        srad_omp_1(E_C, W_C, N_C, S_C, J, c, cols, rows, q0sqr);
        srad_omp_2(E_C, W_C, N_C, S_C, J, c, cols, rows, lambda, q0sqr);
    }

#ifdef OUTPUT
    printf("Printing Output:\n");
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    free(J);
    free(E_C);
    free(W_C);
    free(N_C);
    free(S_C);
    free(c);
}

void random_matrix(float *I, int rows, int cols)
{
    srand(7);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
        }
    }
}
